// 날짜 계산: 전일(어제) + 이번 달 + 올해 + 전년 동기
let body = {};
try { body = $('수동 조회').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');

const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

const yesterday = new Date(kstNow);
yesterday.setDate(yesterday.getDate() - 1);

const yDate = yesterday.toISOString().slice(0, 10);
const yYear = yDate.slice(0, 4);
const yMonth = yDate.slice(0, 7);
const prevYear = String(parseInt(yYear) - 1);
const prevYearMonth = prevYear + yDate.slice(4, 7);

const p = yDate.split('-').map(Number);
const target = new Date(Date.UTC(p[0], p[1]-1, p[2]));
const jan1 = new Date(Date.UTC(parseInt(yYear), 0, 1));
const sheetsRow = Math.round((target - jan1) / 86400000) + 2;

const dowNames = ['일','월','화','수','목','금','토'];
const dow = dowNames[yesterday.getDay()];
const m = yesterday.getMonth() + 1;
const d = yesterday.getDate();
const mtdDays = d;

return [{ json: {
  chatId, yDate, yYear, yMonth, prevYear, prevYearMonth,
  sheetsRow, dow, monthNum: m, dayNum: d, mtdDays,
  label: `${m}/${d}(${dow}) 확정`,
} }];

// 자동 채널은 NocoDB(F23 수집 결과)를 우선 사용하고, 로켓/기타만 Sheets 수동값 사용
const dateInfo = $('날짜 계산').first().json;
const sheetResp = $('Sheets 전일 행 조회').first().json || {};
const cyResp = $('올해 NocoDB 조회').first().json || {};
const cyList = cyResp.list || [];

let row = [];
try {
  const values = sheetResp.values || [[]];
  row = values[0] || [];
} catch(e) {}

const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  const s = String(v).replace(/[^0-9.-]/g, '');
  return parseInt(s) || 0;
};

// 해당 날짜 NocoDB 최신 레코드 찾기 (F23이 쿠팡윙 API 결과를 저장)
let target = null;
for (const r of cyList) {
  if (r.report_date === dateInfo.yDate) {
    if (!target || r.Id > target.Id) target = r;
  }
}

const fromRecord = !!target;
const ms = fromRecord ? num(target.makeshop_revenue) : num(row[0]);
const nv = fromRecord ? num(target.naver_revenue) : num(row[1]);
const st = fromRecord ? num(target.st11_revenue) : num(row[2]);
const crm = fromRecord ? num(target.crm_revenue) : num(row[3]);
const coupang = fromRecord ? num(target.coupang_revenue) : num(row[4]);
const coupangOrders = fromRecord ? num(target.coupang_orders) : 0;

// G열(쿠팡윙)은 이제 F23 API 자동값이므로 수동 입력으로 보지 않음.
// H/I열(로켓배송/기타)은 당분간 수동 보정 채널로 유지.
const rocket = num(row[5]);
const etc = num(row[6]);
const sheetTotal = num(row[7]);
const manualEntered = (row.length >= 7) && (row[5] !== '' || row[6] !== '');
const todayTotal = ms + nv + st + crm + coupang + rocket + etc;

return [{ json: {
  sheetRow: row, makeshop: ms, naver: nv, st11: st, crm: crm,
  coupang: coupang, coupangOrders, rocket: rocket, etc: etc,
  sheetTotal, todayTotal, manualEntered, dateInfo,
  autoSource: fromRecord ? 'nocodb_f23_api' : 'sheet_fallback',
  targetRecordId: target ? target.Id : null,
} }];

// NocoDB 로켓/기타 수동채널 동기화
// 쿠팡윙은 F23에서 OpenAPI로 저장되므로 Sheets 수동값으로 덮어쓰지 않는다.
const parsed = $('Sheet 행 파싱').first().json;
const di = parsed.dateInfo;

if (!parsed.manualEntered) {
  return [{ json: { ...parsed, patchResult: 'skipped_no_manual_rocket_etc' } }];
}

