let target = null;
for (const r of cyList) {
  if (r.report_date === di.yDate) {
    if (!target || r.Id > target.Id) target = r;
  }
}

if (!target) {
  return [{ json: { ...parsed, patchResult: 'no_record_' + di.yDate } }];
}

