const autoNv = parseInt(target.naver_revenue || 0);
const autoSt = parseInt(target.st11_revenue || 0);
const autoCrm = parseInt(target.crm_revenue || 0);
const autoCoupang = parseInt(target.coupang_revenue || 0);
const newTotal = autoMs + autoNv + autoSt + autoCrm + autoCoupang + parsed.rocket + parsed.etc;

try {
