    method: 'PATCH',
    url: 'https://nocodb.pressco21.com/api/v2/tables/mwxvxjiqtw177xu/records',
    headers: {
      'xc-token': $env.NOCODB_TOKEN,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify([{
      Id: target.Id,
      rocket_revenue: parsed.rocket,
      legacy_others_revenue: parsed.etc,
      total_revenue: newTotal,
    }]),
  });
  return [{ json: { ...parsed, todayTotal: newTotal, patchResult: 'patched_Id=' + target.Id } }];
} catch (e) {
  return [{ json: { ...parsed, patchResult: 'error:' + e.message } }];
