msg += `일평균 ${fmt(avgByElapsed)}원`;
if (bestDay) msg += ` · 최고일 ${dateLabel(bestDay.date)} ${fmt(bestDay.rev)}원`;
if (bestWeekday) msg += `\n강한 요일 ${bestWeekday}요일 평균 ${fmt(bestWeekdayAvg)}원`;
if (progressVsPrevFull) msg += `\n전년 동월 전체 대비 ${progressVsPrevFull} 진행`;
if (yearVsPrev) msg += `\n올해 누계 전년동시점 ${yearVsPrev}`;
msg += `\n\n<b>어제 채널별 매출</b>\n`;
for (const c of channels) msg += `${c.name} ${fmt(c.amount)}원 (${pct(c.amount, yesterdayTotal)})\n`;
msg += `\n상세 내용은 아래 버튼에서 확인하세요.`;
